body:
Consider the following example:
```sv
module driver(
    input logic clk,
    output logic data
);

task write_32(input logic [31:0] data);
    for (int i = 0; i < 32; i = i + 1) begin
        #1; data <= w_data[i]; @(posedge clk);
    end
endtask

task l1(input logic [31:0] data);
    #1; drv.write_32(data); @(posedge clk);
    #1; drv.write_32(data); @(posedge clk);
    #1; drv.write_32(data); @(posedge clk);
    #1; drv.write_32(data); @(posedge clk);
endtask

task l2(input logic [31:0] data);
    #1; l1(data + 0); @(posedge clk);
    #1; l1(data + 1); @(posedge clk);
    #1; l1(data + 2); @(posedge clk);
    #1; l1(data + 3); @(posedge clk);
endtask

task l3(input logic [31:0] data);
    #1; l2(data + 0); @(posedge clk);
    #1; l2(data + 1); @(posedge clk);
    #1; l2(data + 2); @(posedge clk);
    #1; l2(data + 3); @(posedge clk);
endtask

task l4(input logic [31:0] data);
    #1; l3(data + 0); @(posedge clk);
    #1; l3(data + 1); @(posedge clk);
    #1; l3(data + 2); @(posedge clk);
    #1; l3(data + 3); @(posedge clk);
endtask

endmodule;

module top();
    wire clk, data;
    driver drv(
        .clk(clk),
        .data(data)
    );
    
    initial begin
        for (int i = 0; i < 10; i = i + 1) begin
            drv.l4(32'h12345678);
        end
    end
endmodule
```

When attempting to verilate this code with Verilator on master ( ``verilator --trace --exe --build -j `nproc` --binary inline_performance.sv -o inline_performance``, it produces an almost 100k line-long .cpp file (`Vinline_performance___024root__DepSet_h5fbe98ea__0.cpp`), on which the C++ compiler then hangs indefinitely.

Note that removing the for loop on line 50 allows Verilator to split up the file into multiple smaller chunks.

In this specific case, `--unroll-count 1` helps reduce the code size because the loop inside `write_32` no longer becomes unrolled, but in general this isn't a solution.

I suppose there are two approaches for a fix:
- Either, don't always automatically inline tasks (though I'm not sure if it is even currently possible to have such non-inlined tasks, but I do think this would be a cleaner solution in general...) or
- Implement splitting up code inside a for loop
